  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { OpencodeConfig } from "./config-builder";
  3→import { buildOpencodeConfig } from "./config-builder";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→
  9→// ---------------------------------------------------------------------------
 10→// Types — exported for tests
 11→// ---------------------------------------------------------------------------
 12→
 13→export type OpenCodeHandle = {
 14→  sessionId: string;
 15→  abort: () => void;
 16→  sendPrompt: (text: string) => Promise<void>;
 17→  eventStream: AsyncIterable<unknown>;
 18→};
 19→
 20→export type SpawnOpenCodeFn = (
 21→  config: OpencodeConfig,
 22→  worktreePath: string,
 23→  taskId: string,
 24→) => Promise<OpenCodeHandle>;
 25→
 26→export type SessionDeps = {
 27→  surreal: Surreal;
 28→  shellExec: ShellExec;
 29→  brainBaseUrl: string;
 30→  spawnOpenCode?: SpawnOpenCodeFn;
 31→};
 32→
 33→export type SessionErrorCode =
 34→  | "TASK_NOT_FOUND"
 35→  | "TASK_NOT_ASSIGNABLE"
 36→  | "AGENT_ALREADY_ACTIVE"
 37→  | "WORKSPACE_MISMATCH"
 38→  | "MISSING_TASK_ID"
 39→  | "WORKTREE_ERROR"
 40→  | "SESSION_NOT_FOUND"
 41→  | "SESSION_ERROR";
 42→
 43→export type SessionError = {
 44→  code: SessionErrorCode;
 45→  message: string;
 46→  httpStatus: number;
 47→};
 48→
 49→export type SessionResult<T> =
 50→  | { ok: true; value: T }
 51→  | { ok: false; error: SessionError };
 52→
 53→export type OrchestratorSessionResult = SessionResult<{
 54→  agentSessionId: string;
 55→  streamId: string;
 56→  worktreeBranch: string;
 57→}>;
 58→
 59→export type SessionStatusResult = SessionResult<{
 60→  orchestratorStatus: OrchestratorStatus;
 61→  worktreeBranch?: string;
 62→  worktreePath?: string;
 63→  lastEventAt?: string;
 64→  startedAt?: string;
 65→  error?: string;
 66→}>;
 67→
 68→export type AbortSessionResult = SessionResult<{
 69→  aborted: boolean;
 70→  sessionId: string;
 71→}>;
 72→
 73→export type AcceptSessionResult = SessionResult<{
 74→  accepted: boolean;
 75→  sessionId: string;
 76→}>;
 77→
 78→export type ReviewResult = SessionResult<{
 79→  taskTitle: string;
 80→  diff: import("./worktree-manager").DiffResult;
 81→  session: {
 82→    orchestratorStatus: string;
 83→    worktreeBranch?: string;
 84→    startedAt?: string;
 85→    lastEventAt?: string;
 86→    toolCallCount?: number;
 87→    filesEdited?: number;
 88→  };
 89→}>;
 90→
 91→export type RejectSessionResult = SessionResult<{
 92→  rejected: boolean;
 93→  continuing: boolean;
 94→}>;
 95→
 96→// ---------------------------------------------------------------------------
 97→// In-memory handle registry — maps agentSessionId to OpenCodeHandle
 98→// ---------------------------------------------------------------------------
 99→
100→const handleRegistry = new Map<string, OpenCodeHandle>();
101→
102→// Exported for testing cleanup
103→export function clearHandleRegistry(): void {
104→  handleRegistry.clear();
105→}
106→
107→// ---------------------------------------------------------------------------
108→// Pure helpers
109→// ---------------------------------------------------------------------------
110→
111→function sessionNotFound(sessionId: string): SessionError {
112→  return {
113→    code: "SESSION_NOT_FOUND",
114→    message: `Session not found: ${sessionId}`,
115→    httpStatus: 404,
116→  };
117→}
118→
119→function worktreeError(message: string): SessionError {
120→  return {
121→    code: "WORKTREE_ERROR",
122→    message,
123→    httpStatus: 500,
124→  };
125→}
126→
127→function fromAssignmentError(error: AssignmentError): SessionError {
128→  return {
129→    code: error.code as SessionErrorCode,
130→    message: error.message,
131→    httpStatus: error.httpStatus,
132→  };
133→}
134→
135→type SessionLookup =
136→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
137→  | { ok: false; error: SessionError };
138→
139→async function lookupSession(
140→  surreal: Surreal,
141→  sessionId: string,
142→): Promise<SessionLookup> {
143→  const record = new RecordId("agent_session", sessionId);
144→  const session = await surreal.select<SessionRow>(record);
145→  if (!session) {
146→    return { ok: false, error: sessionNotFound(sessionId) };
147→  }
148→  if (!session.orchestrator_status) {
149→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
150→  }
151→  const status = session.orchestrator_status as OrchestratorStatus;
152→  return { ok: true, session, record, status };
153→}
154→
155→function generateStreamId(sessionId: string): string {
156→  return `stream-${sessionId}`;
157→}
158→
159→function slugFromTitle(title: string): string {
160→  return title
161→    .toLowerCase()
162→    .replace(/[^a-z0-9]+/g, "-")
163→    .replace(/^-|-$/g, "")
164→    .slice(0, 50);
165→}
166→
167→// ---------------------------------------------------------------------------
168→// Session row shape (DB query result)
169→// ---------------------------------------------------------------------------
170→
171→type SessionRow = {
172→  id: RecordId<"agent_session", string>;
173→  orchestrator_status?: string;
174→  worktree_branch?: string;
175→  worktree_path?: string;
176→  started_at?: string;
177→  last_event_at?: string;
178→  task_id?: RecordId<"task", string>;
179→  workspace?: RecordId<"workspace", string>;
180→  error?: string;
181→};
182→
183→// ---------------------------------------------------------------------------
184→// createOrchestratorSession
185→// ---------------------------------------------------------------------------
186→
187→type CreateSessionInput = {
188→  surreal: Surreal;
189→  shellExec: ShellExec;
190→  brainBaseUrl: string;
191→  workspaceId: string;
192→  taskId: string;
193→  authToken: string;
194→  spawnOpenCode?: SpawnOpenCodeFn;
195→  validateAssignment: (
196→    surreal: Surreal,
197→    workspaceId: string,
198→    taskId: string,
199→  ) => Promise<AssignmentResult>;
200→  createAgentSession: (input: {
201→    surreal: Surreal;
202→    agent: string;
203→    workspaceRecord: RecordId<"workspace", string>;
204→    taskId?: string;
205→  }) => Promise<{ session_id: string }>;
206→};
207→
208→export async function createOrchestratorSession(
209→  input: CreateSessionInput,
210→): Promise<OrchestratorSessionResult> {
211→  // 1. Validate assignment eligibility
212→  const assignmentResult = await input.validateAssignment(
213→    input.surreal,
214→    input.workspaceId,
215→    input.taskId,
216→  );
217→
218→  if (!assignmentResult.ok) {
219→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
220→  }
221→
222→  const { validation } = assignmentResult;
223→  const taskSlug = slugFromTitle(validation.title);
224→  const repoRoot = validation.repoPath;
225→
226→  // 2. Create worktree
227→  const worktreeResult = await createWorktree(
228→    input.shellExec,
229→    repoRoot,
230→    taskSlug,
231→  );
232→
233→  if (!worktreeResult.ok) {
234→    return {
235→      ok: false,
236→      error: worktreeError(worktreeResult.error.message),
237→    };
238→  }
239→
